-- ─── 4. Reporte (NOTICE) ──────────────────────────────────────────────────
DO $report$
DECLARE
  v_total INTEGER;
  v_devops INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_total FROM public.support_tickets;
  SELECT COUNT(*) INTO v_devops FROM public.support_tickets WHERE fuente = 'devops';
  RAISE NOTICE 'Total tickets: %, de los cuales fuente=devops: %', v_total, v_devops;
END;
$report$;
